mapper.select:
select u.user_id, u.username, u.nickname, u.dept_id, d.dept_name, u.phone, u.email, u.status, u.super_admin from sys_user u left join sys_dept d on d.dept_id = u.dept_id where u.deleted = 0
and u.username like concat('%', #{query.username}, '%')
and u.nickname like concat('%', #{query.nickname}, '%')
and u.dept_id = #{query.deptId}
and u.status = #{query.status}
order by u.user_id desc
